import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { PieChart } from '@mui/x-charts';
import response from './response.json';

interface InvoiceSummary {
  totalInvoices: number;
  pending: {
    count: number;
    amount: number;
  };
  paid: {
    count: number;
    amount: number;
  };
  overdue: {
    count: number;
    amount: number;
  };
}

interface InvoiceStatus {
  status: string;
  count: number;
}

interface InvoiceData {
  summary: InvoiceSummary;
  invoiceStatus: InvoiceStatus[];
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
  chartTypes: string[];
}

export default function Widget() {
  const invoiceData = response.data as InvoiceData;
  const metaData = response.meta as MetaData;

  const chartData = invoiceData.invoiceStatus.map(status => ({
    id: status.status,
    value: status.count,
    label: status.status,
  }));

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: metaData.primaryColor }}>
              Invoice Summary
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
              Total Invoices: {invoiceData.summary.totalInvoices}
            </Typography>
            <Stack direction="row" spacing={0.5}>
              <Chip label={`Pending: ${invoiceData.summary.pending.count}`} sx={{ fontSize: '11px', backgroundColor: metaData.primaryColor, color: '#FFFFFF', px: 1, py: 0.5 }} />
              <Chip label={`Paid: ${invoiceData.summary.paid.count}`} sx={{ fontSize: '11px', backgroundColor: '#4CAF50', color: '#FFFFFF', px: 1, py: 0.5 }} />
              <Chip label={`Overdue: ${invoiceData.summary.overdue.count}`} sx={{ fontSize: '11px', backgroundColor: metaData.accentColor, color: '#FFFFFF', px: 1, py: 0.5 }} />
            </Stack>
          </Box>

          <PieChart
            height={200}
            data={chartData}
            series={[
              {
                innerRadius: 0.6,
                outerRadius: 1,
                cx: '50%',
                cy: '50%',
                label: {
                  visible: true,
                  field: 'label',
                  placement: 'auto',
                  fontSize: 10,
                  color: '#333',
                },
                valueField: 'value',
                nameField: 'id',
                colorField: 'id',
                color: [metaData.primaryColor, '#4CAF50', metaData.accentColor],
              }
            ]}
            margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
